INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8bcc588d-0ba3-45da-9120-850b1b768c4b',
  '00000000-0000-0000-0000-000000000001',
  $escape$ethers_js + IPFS — Reading CIDs from NFT Contracts and Resolving Off-Chain Metadata$escape$,
  $escape$IPFS stores content by what it is, not where it is. A CID (Content Identifier) is a multihash of the data — change one byte, get a new CID. This makes on-chain NFT metadata tamper-evident: the `tokenURI()` return value in an ERC-721 contract is typically `ipfs://QmXoypiz...` (CIDv0) or `ipfs://bafy...` (CIDv1 base32).

When you call `contract.tokenURI(tokenId)` via ethers.js, you receive a raw `ipfs://` URI — not an HTTP URL. ethers.js has no built-in IPFS resolver; strip the prefix and query a gateway yourself. The DHT routes your request to peers holding that CID, but peers are not obligated to persist it. Pinning explicitly instructs a node — yours, Pinata, or web3.storage — to keep it alive.

IPFS vs Filecoin: IPFS is the content-addressing protocol and DHT routing layer; Filecoin adds cryptographic storage proofs (PoRep/PoSt) and token incentives so storage providers are paid to retain CIDs long-term. For production NFT projects, pin via Filecoin-backed services (NFT.Storage, w3up) rather than relying on public DHT availability.

The CID your contract stores on-chain is the immutable anchor — gateway URLs are ephemeral convenience wrappers around it.$escape$,
  $escape$import { ethers } from "ethers";

const provider = new ethers.JsonRpcProvider(process.env.RPC_URL);
const abi = ["function tokenURI(uint256 tokenId) view returns (string)"];
const bayc = new ethers.Contract(
  "0xBC4CA0EdA7647A8aB7C2061c2E118A18a936f13D",
  abi,
  provider
);

const uri = await bayc.tokenURI(1n);
// "ipfs://QmeSjSinHpPnmXmspMjwiXyN6zS4E9zccariGR3jxcaWtq/1"

const cid = uri.replace("ipfs://", "");
const metadata = await fetch(`https://ipfs.io/ipfs/${cid}`).then(r => r.json());
console.log(metadata.image); // another ipfs:// URI for the actual asset$escape$,
  $escape$typescript$escape$,
