INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3ac88120-4a52-4840-96da-e63fa7c9abca',
  '00000000-0000-0000-0000-000000000001',
  $escape$ethers.js Transaction Mastery — Signing, Gas, Nonces, and Monitoring$escape$,
  $escape$ethers.js gives you fine-grained control over every transaction lifecycle stage. When sending a transaction, `provider.getFeeData()` returns `maxFeePerGas` and `maxPriorityFeePerGas` for EIP-1559 chains — use these instead of hardcoding `gasPrice`. Call `provider.estimateGas(txRequest)` with your populated transaction object to get an accurate gas limit; add a 20% buffer for volatile contracts. Nonce management is critical under load: fetch once with `signer.getNonce('pending')` (not `'latest'`) to account for in-flight transactions, then manually increment across batched sends. Never rely on auto-nonce when firing multiple transactions in a tight loop — ethers will re-fetch and collide. After broadcasting via `signer.sendTransaction()`, you get a `TransactionResponse`. Call `.wait(confirmations)` to block until mined — it returns a `TransactionReceipt` with `status` (1 = success, 0 = reverted). For real-time monitoring without blocking, attach to `provider.once('transaction', hash, callback)` or poll `provider.getTransactionReceipt(hash)` until non-null. Always check `receipt.status` — a mined transaction can still be a revert.$escape$,
  $escape$import { ethers } from 'ethers';

const provider = new ethers.JsonRpcProvider(RPC_URL);
const signer = new ethers.Wallet(PRIVATE_KEY, provider);

const feeData = await provider.getFeeData();
const nonce = await signer.getNonce('pending');

const txRequest = {
  to: '0xRecipient...',
  value: ethers.parseEther('0.01'),
  nonce,
  maxFeePerGas: feeData.maxFeePerGas,
  maxPriorityFeePerGas: feeData.maxPriorityFeePerGas,
};

txRequest.gasLimit = (await provider.estimateGas(txRequest)) * 120n / 100n;

const tx = await signer.sendTransaction(txRequest);
const receipt = await tx.wait(1);

if (receipt.status === 0) throw new Error(`Reverted: ${tx.hash}`);$escape$,
  $escape$typescript$escape$,
