INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '11fe51ea-282f-4bf8-9b14-3d0ef78326b2',
  '00000000-0000-0000-0000-000000000001',
  $escape$ethers.js to viem — Why Modern Stacks Are Dropping ethers.js$escape$,
  $escape$If you've built with ethers.js v5 or v6, you know the pain: a 116 kB bundle, a class-heavy OOP API, and TypeScript types that require constant casting. viem solves all three. It's tree-shakeable by default — import only `getBalance` and that's all you ship. Its API is function-based, not class-based, so there's no `new ethers.providers.JsonRpcProvider()` ceremony. Instead: `createPublicClient({ transport: http(rpcUrl) })`.

The real win is type safety. viem infers ABI types end-to-end — if your ABI says a function returns `uint256`, TypeScript knows the return type is `bigint` without any casting. ethers.js v6 improved this with `TypedContract`, but viem bakes it in natively with zero boilerplate.

Performance-wise, viem uses native `bigint` throughout (no `BigNumber` wrapper), and its bundle is ~35 kB vs ethers.js v6's ~80 kB. Migration is straightforward: `Provider` → `PublicClient`, `Signer` → `WalletClient`, `Contract` → `getContract`. Most ethers.js mental models transfer directly — the API surface just gets leaner and more explicit.$escape$,
  $escape$import { createPublicClient, createWalletClient, http, getContract } from 'viem'
import { mainnet } from 'viem/chains'
import { privateKeyToAccount } from 'viem/accounts'

// ethers.js: new ethers.providers.JsonRpcProvider(rpcUrl)
const publicClient = createPublicClient({ chain: mainnet, transport: http(process.env.RPC_URL) })

// ethers.js: new ethers.Wallet(privateKey, provider)
const account = privateKeyToAccount(`0x${process.env.PRIVATE_KEY}`)
const walletClient = createWalletClient({ account, chain: mainnet, transport: http(process.env.RPC_URL) })

// ethers.js: new ethers.Contract(address, abi, signer)
const contract = getContract({ address: '0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48', abi, client: { public: publicClient, wallet: walletClient } })

// Return type is bigint — no BigNumber, no casting
const balance: bigint = await contract.read.balanceOf([account.address])$escape$,
  $escape$typescript$escape$,
